import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import toast from 'react-hot-toast';
import { LayoutDashboard, Calendar, Users, LogOut, Activity, User, Heart, CheckCircle, Clock, MapPin, FileText } from 'lucide-react';

const API = "http://localhost:5000/api";

export default function CaregiverDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('overview');
  const [bookings, setBookings] = useState([]);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [updateMsg, setUpdateMsg] = useState('');
  const [selectedBooking, setSelectedBooking] = useState(null);

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    const token = localStorage.getItem("token");

    try {
      const [bRes, pRes] = await Promise.all([
        axios.get(`${API}/bookings/my-bookings`, {
          headers: { Authorization: `Bearer ${token}` }
        }),
        axios.get(`${API}/caregivers/me`, {
          headers: { Authorization: `Bearer ${token}` }
        }).catch(() => ({ data: null }))
      ]);

      setBookings(bRes.data);
      setProfile(pRes.data);

    } catch (err) {
      console.log(err);
      toast.error('Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  const updateStatus = async (id, status) => {
    const token = localStorage.getItem("token");

    try {
      await axios.patch(
        `${API}/bookings/${id}/status`,
        { status },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      toast.success('Status updated');
      fetchData();

    } catch {
      toast.error('Failed to update status');
    }
  };

  const addHealthUpdate = async (id) => {
    const token = localStorage.getItem("token");

    if (!updateMsg.trim()) return;

    try {
      await axios.post(
        `${API}/bookings/${id}/health-update`,
        { message: updateMsg },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      toast.success('Update sent');
      setUpdateMsg('');
      fetchData();

    } catch {
      toast.error('Failed to send update');
    }
  };

  const assigned = bookings.filter(b => b.status === 'assigned');
  const active = bookings.filter(b => b.status === 'active');
  const completed = bookings.filter(b => b.status === 'completed');

  return (
    <div className="dashboard-layout">

      {/* SIDEBAR */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <Heart size={18} /> Prana Solutions
        </div>

        <div className="sidebar-nav">
          <div className="sidebar-item" onClick={() => setActiveTab('overview')}>
            <LayoutDashboard size={18}/> Overview
          </div>
          <div className="sidebar-item" onClick={() => setActiveTab('patients')}>
            <Users size={18}/> Patients
          </div>
          <div className="sidebar-item" onClick={() => setActiveTab('schedule')}>
            <Calendar size={18}/> Schedule
          </div>
          <div className="sidebar-item" onClick={() => setActiveTab('updates')}>
            <Activity size={18}/> Updates
          </div>
          <div className="sidebar-item" onClick={() => setActiveTab('profile')}>
            <User size={18}/> Profile
          </div>
        </div>

        <div style={{ marginTop: 'auto' }}>
          <div className="sidebar-item" onClick={() => { logout(); navigate('/'); }}>
            <LogOut size={18}/> Logout
          </div>
        </div>
      </aside>

      {/* MAIN */}
      <main className="main-content">

        {/* OVERVIEW */}
        {activeTab === 'overview' && (
          <>
            <div className="page-header">
              <h1 className="page-title">Welcome {user?.name}</h1>
            </div>

            <div className="stats-grid">
              <div className="card stat-card">
                <div className="stat-value">{bookings.length}</div>
                <div className="stat-label">Total</div>
              </div>
              <div className="card stat-card">
                <div className="stat-value">{assigned.length}</div>
                <div className="stat-label">Assigned</div>
              </div>
              <div className="card stat-card">
                <div className="stat-value">{active.length}</div>
                <div className="stat-label">Active</div>
              </div>
              <div className="card stat-card">
                <div className="stat-value">{completed.length}</div>
                <div className="stat-label">Completed</div>
              </div>
            </div>
          </>
        )}

        {/* PATIENTS */}
        {activeTab === 'patients' && (
          <>
            <h2 className="section-title">My Patients</h2>

            {bookings.map(b => (
              <div key={b._id} className="card p-4" style={{ marginBottom: 10 }}>
                <p><b>{b.patient?.name}</b></p>
                <p>{b.careType}</p>

                {b.status === 'assigned' && (
                  <button className="btn btn-primary"
                    onClick={() => updateStatus(b._id, 'active')}>
                    Start
                  </button>
                )}

                {b.status === 'active' && (
                  <button className="btn btn-primary"
                    onClick={() => updateStatus(b._id, 'completed')}>
                    Complete
                  </button>
                )}
              </div>
            ))}
          </>
        )}

      </main>
    </div>
  );
}
